  1→import { useCallback } from 'react';
  2→import { NavViewData, TRAY_COMMAND_MAP } from './app_types';
  3→import { CommandPalette } from './components/command_palette/command_palette';
  4→import { DetailItemView } from './components/detail/detail_item_view';
  5→import { RootSearchView } from './components/root_search/root_search_view';
  6→import {
  7→  NavigationContextProvider,
  8→  useNavigationStack,
  9→} from './hooks/use_navigation';
 10→import { useTheme } from './hooks/use_theme';
 11→import { useWindow } from './hooks/use_window';
 12→import { getCommand } from './registry';
 13→
 14→function renderNavView(data: NavViewData) {
 15→  if (data.type === 'command') {
 16→    const cmd = getCommand(data.commandId);
 17→    if (cmd?.component) {
 18→      const Component = cmd.component;
 19→      return <Component />;
 20→    }
 21→    return null;
 22→  }
 23→
 24→  if (data.type === 'detail') {
 25→    return <DetailItemView item={data.item} />;
 26→  }
 27→
 28→  return null;
 29→}
 30→
 31→export function App() {
 32→  useTheme();
 33→  const nav = useNavigationStack<NavViewData>('Raycast');
 34→  const { push, popToRoot } = nav;
 35→
 36→  const handleTrayNavigate = useCallback(
 37→    (target: string) => {
 38→      const mapping = TRAY_COMMAND_MAP[target];
 39→      if (!mapping) return;
 40→
 41→      const cmd = getCommand(mapping.id);
 42→      if (!cmd?.component) return;
 43→
 44→      popToRoot();
 45→      push(mapping.name, {
 46→        type: 'command',
 47→        commandId: mapping.id,
 48→      });
 49→    },
 50→    [
 51→      push,
 52→      popToRoot,
 53→    ],
 54→  );
 55→
 56→  useWindow({
 57→    onShow: () => {
 58→      const input =
 59→        document.querySelector<HTMLInputElement>('.search-bar__input');
 60→      input?.focus();
 61→    },
 62→    onHide: () => {
 63→      popToRoot();
 64→    },
 65→    onTrayNavigate: handleTrayNavigate,
 66→  });
 67→
 68→  const currentNavData = nav.currentEntry?.data;
 69→  const isFullView =
 70→    currentNavData?.type === 'command' &&
 71→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 72→
 73→  const navDirectionClass =
 74→    nav.direction === 'push'
 75→      ? ' command-palette__nav-view--push'
 76→      : nav.direction === 'pop'
 77→        ? ' command-palette__nav-view--pop'
 78→        : '';
 79→
 80→  const isRoot = !currentNavData;
 81→
 82→  return (
 83→    <NavigationContextProvider value={nav}>
 84→      <CommandPalette isLoading compact={isRoot}>
 85→        {isFullView && nav.currentEntry ? (
 86→          <div
 87→            key={nav.navKey}
 88→            className={`command-palette__nav-view${navDirectionClass}`}
 89→          >
 90→            {renderNavView(nav.currentEntry.data)}
 91→          </div>
 92→        ) : nav.currentEntry ? (
 93→          <div
 94→            key={nav.navKey}
 95→            className={`command-palette__nav-view${navDirectionClass}`}
 96→          >
 97→            <div className="command-palette__body">
 98→              <div className="command-palette__list-container">
 99→                {renderNavView(nav.currentEntry.data)}
100→              </div>
101→            </div>
102→          </div>
103→        ) : (
104→          <RootSearchView />
105→        )}
106→      </CommandPalette>
107→    </NavigationContextProvider>
108→  );
109→}
