 58→function flattenItems(sections: SectionData[]): ListItemData[] {
 59→  return sections.flatMap(s => s.items);
 60→}
 61→
 62→const searchFilterSections: SearchDropdownSection[] = [
 63→  {
 64→    options: [
 65→      {
 66→        label: 'All',
 67→        value: 'all',
 68→      },
 69→    ],
 70→  },
 71→  {
 72→    title: 'Types',
 73→    options: [
 74→      {
 75→        label: 'Commands',
 76→        value: 'commands',
