  1→import { useEffect, useRef } from 'react';
  2→
  3→export interface KeyCombo {
  4→  key: string;
  5→  meta?: boolean;
  6→  ctrl?: boolean;
  7→  alt?: boolean;
  8→  shift?: boolean;
  9→}
 10→
 11→export interface ShortcutOptions {
 12→  enabled?: boolean;
 13→  preventDefault?: boolean;
 14→}
 15→
 16→type ComboKey = string;
 17→
 18→function comboToKey(combo: KeyCombo): ComboKey {
 19→  const parts: string[] = [];
 20→  if (combo.meta) parts.push('meta');
 21→  if (combo.ctrl) parts.push('ctrl');
 22→  if (combo.alt) parts.push('alt');
 23→  if (combo.shift) parts.push('shift');
 24→  parts.push(combo.key.toLowerCase());
 25→  return parts.join('+');
 26→}
 27→
 28→const activeShortcuts = new Map<ComboKey, number>();
 29→
 30→function hasModifier(combo: KeyCombo): boolean {
 31→  return !!(combo.meta || combo.ctrl || combo.alt || combo.shift);
 32→}
 33→
 34→function registerCombo(combo: KeyCombo): ComboKey {
 35→  const key = comboToKey(combo);
 36→  if (import.meta.env.DEV && !hasModifier(combo)) {
 37→    console.warn(
 38→      `[useKeyboardShortcut] Shortcut "${key}" has no modifier keys. ` +
 39→        `This will fire while typing in inputs.`,
 40→    );
 41→  }
 42→  const count = activeShortcuts.get(key) ?? 0;
 43→  if (import.meta.env.DEV && count > 0) {
 44→    console.warn(
 45→      `[useKeyboardShortcut] Duplicate shortcut registered: ${key}. ` +
 46→        `Both handlers will fire for this combo.`,
 47→    );
 48→  }
 49→  activeShortcuts.set(key, count + 1);
 50→  return key;
 51→}
 52→
 53→function unregisterCombo(key: ComboKey) {
 54→  const count = activeShortcuts.get(key) ?? 0;
 55→  if (count <= 1) {
 56→    activeShortcuts.delete(key);
 57→  } else {
 58→    activeShortcuts.set(key, count - 1);
 59→  }
 60→}
 61→
 62→function matchesCombo(e: KeyboardEvent, combo: KeyCombo): boolean {
 63→  if (e.key.toLowerCase() !== combo.key.toLowerCase()) return false;
 64→  if (!!combo.meta !== e.metaKey) return false;
 65→  if (!!combo.ctrl !== e.ctrlKey) return false;
 66→  if (!!combo.alt !== e.altKey) return false;
 67→  if (!!combo.shift !== e.shiftKey) return false;
 68→  return true;
 69→}
 70→
 71→export type ShortcutHandler = (e: KeyboardEvent) => void;
 72→
 73→export function useKeyboardShortcut(
 74→  combo: KeyCombo,
 75→  handler: ShortcutHandler | (() => void),
 76→  options?: ShortcutOptions,
 77→): void {
 78→  const handlerRef = useRef(handler);
 79→  handlerRef.current = handler;
 80→
 81→  const enabled = options?.enabled ?? true;
 82→  const preventDefault = options?.preventDefault ?? true;
 83→
 84→  useEffect(() => {
 85→    if (!enabled) return;
 86→
 87→    const comboKey = registerCombo(combo);
 88→
 89→    function handleKeyDown(e: KeyboardEvent) {
 90→      if (matchesCombo(e, combo)) {
 91→        if (preventDefault) {
 92→          e.preventDefault();
 93→        }
 94→        handlerRef.current(e);
 95→      }
 96→    }
 97→
 98→    window.addEventListener('keydown', handleKeyDown);
 99→    return () => {
100→      window.removeEventListener('keydown', handleKeyDown);
101→      unregisterCombo(comboKey);
102→    };
103→  }, [
104→    combo.key,
105→    combo.meta,
106→    combo.ctrl,
107→    combo.alt,
108→    combo.shift,
109→    enabled,
110→    preventDefault,
111→  ]);
112→}
